external_knowledge:
- 'Navigators' metaphorically refer to 'users';
- 'Exploring the land of BrandA' is a metaphor for accessing 'BrandA' size charts;
- 'Frequency of their voyages' represents the number of times a user has accessed the size charts;
- The top 10 'navigators' are limited to those who have a defined role in the company.

sql:
SELECT sc.gender, sc.size_chart_type, pc.category_name
FROM size_charts sc
JOIN product_categories pc ON sc.category_id = pc.category_id;

SELECT *
FROM chart_metadata
WHERE status = 'inactive';

SELECT DISTINCT b.brand_name
FROM brands b
JOIN size_charts s ON b.brand_id = s.brand_id;

SELECT COUNT(DISTINCT brand_id) 
FROM size_charts 
WHERE gender = 'men';

SELECT country_of_origin, GROUP_CONCAT(DISTINCT brand_name) AS Brand_Names
FROM brands
GROUP BY country_of_origin;
